import s from "./s.svg";
import { animatedRouter, html, navigateTo, pathAtom } from "mates";
import type { Props } from "mates";

function nav(path: string, label: string) {
  const active = pathAtom() === path;
  return html`
    <a
      class="demo-nav__link ${active ? "demo-nav__link--active" : ""}"
      href=${path}
      @click=${(event: Event) => {
        event.preventDefault();
        navigateTo(path);
      }}
    >
      ${label}
    </a>
  `;
}

